7	
8	---------------------------------------------------------------------------------------------------
9	-- Description
10	---------------------------------------------------------------------------------------------------
11	-- This entity implements an efficient weighted round-robin arbiter.
12	--
13	-- Documentation:
14	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_arb_wrr.md
15	--
16	-- Note: The link points to the documentation of the latest release. If you
17	--       use an older version, the documentation might not match the code.
18	
19	---------------------------------------------------------------------------------------------------
20	-- Libraries
21	---------------------------------------------------------------------------------------------------
22	library ieee;
23	    use ieee.std_logic_1164.all;
24	    use ieee.numeric_std.all;
25	
26	library work;
27	    use work.olo_base_pkg_array.all;
28	    use work.olo_base_pkg_math.all;
29	    use work.olo_base_pkg_logic.all;
30	
31	---------------------------------------------------------------------------------------------------
32	-- Entity Declaration
33	---------------------------------------------------------------------------------------------------
34	entity olo_base_arb_wrr is
35	    generic (
36	        GrantWidth_g  : positive;
37	        WeightWidth_g : positive;
38	        Latency_g     : natural range 0 to 1 := 0
39	    );
40	    port (
41	        -- Control
42	        Clk        : in    std_logic;
43	        Rst        : in    std_logic;
44	
45	        -- Static Configuration
46	        Weights    : in    std_logic_vector(WeightWidth_g*GrantWidth_g-1 downto 0);
47	
48	        -- Request Interface
49	        In_Valid   : in    std_logic;
50	        In_Req     : in    std_logic_vector(GrantWidth_g-1 downto 0);
51	
52	        -- Grant Interface
53	        Out_Valid  : out   std_logic;
54	        Out_Grant  : out   std_logic_vector(GrantWidth_g-1 downto 0)
55	    );
56	end entity;
57	
58	architecture rtl of olo_base_arb_wrr is
59	
60	    -- Functions
61	    -- Generates a mask for the input request vector.
62	    -- Each bit is set to '1' if the corresponding weight is not zero, otherwise it is '0'.
63	    -- Effectively masks out requests with zero weight.
64	    function generateRequestWeightsMask (
65	        WeightsParam     : std_logic_vector;
66	        WeightWidthParam : positive;
67	        GrantWidthParam  : positive) return std_logic_vector is
68	        -- Variables
69	        variable RequestWeightsMask_v : std_logic_vector(GrantWidthParam-1 downto 0);
70	    begin
71	
72	        for i in (GrantWidthParam-1) downto 0 loop
73	            if (unsigned(WeightsParam((i+1)*WeightWidthParam-1 downto i*WeightWidthParam)) /= 0) then
74	                RequestWeightsMask_v(i) := '1';
75	            else
76	                RequestWeightsMask_v(i) := '0';
77	            end if;
78	        end loop;
79	
80	        return RequestWeightsMask_v;
81	    end function;
82	
83	    -- Two Process Method
84	    type TwoProcess_t is record
85	        Valid      : std_logic;
86	        WeightCnt  : unsigned(WeightWidth_g - 1 downto 0);
87	        Weights    : std_logic_vector(WeightWidth_g * GrantWidth_g - 1 downto 0);
88	        Grant      : std_logic_vector(Out_Grant'range);
89	        GrantIdx   : natural range 0 to GrantWidth_g - 1;
90	        Switchover : std_logic;
91	    end record;
92	
93	    signal r      : TwoProcess_t;
94	    signal r_next : TwoProcess_t;
95	
96	    -- Component connection signals
97	    signal RrReq        : std_logic_vector(In_Req'range);
98	    signal RrGrant      : std_logic_vector(Out_Grant'range);
99	    signal RrGrantReady : std_logic;
100	
101	begin
102	
103	    RrReq <= In_Req and generateRequestWeightsMask(Weights, WeightWidth_g, GrantWidth_g);
104	
105	    -- *** Component Instantiations ***
106	    i_arb_rr : entity work.olo_base_arb_rr
107	        generic map (
108	            Width_g => GrantWidth_g
109	        )
110	        port map (
111	            Clk       => Clk,
112	            Rst       => Rst,
113	            In_Req    => RrReq,
114	            Out_Ready => RrGrantReady,
115	            Out_Grant => RrGrant
116	        );
117	
118	    -----------------------------------------------------------------------------------------------
119	    -- Combinatorial Process
120	    -----------------------------------------------------------------------------------------------
121	    p_comb : process (all) is
122	        variable v                   : TwoProcess_t;
123	        variable WeightCurrent_v     : unsigned(WeightWidth_g - 1 downto 0);
124	        variable WeighsUnflattened_v : StlvArray_t(0 to GrantWidth_g - 1)(WeightWidth_g - 1 downto 0);
125	    begin
126	        -- Hold variables stable
127	        v := r;
128	
129	        -- Valid pipeline
130	        v.Valid := In_Valid;
131	
132	        -- Detect switchover to new requester
133	        if In_Valid = '1' then
134	            v.Weights := Weights;
135	        end if;
136	
137	        -- Switchover detection
138	        WeighsUnflattened_v := unflattenStlvArray(r.Weights, WeightWidth_g);
139	        WeightCurrent_v     := unsigned(WeighsUnflattened_v(r.GrantIdx));
140	        if ((r.WeightCnt >= WeightCurrent_v) and r.Valid = '1') or unsigned(r.Grant and In_Req) = 0 then
141	            v.Switchover := '1';
142	        end if;
143	
144	        -- Switchover Execution
145	        RrGrantReady <= '0';
146	        if (v.Switchover = '1') and (In_Valid = '1') then
147	            v.Switchover := '0';
148	            RrGrantReady <= '1';
149	            if unsigned(RrGrant) = 0 then
150	                v.GrantIdx := 0;
151	            else
152	                v.GrantIdx := getLeadingSetBitIndex(RrGrant);
153	            end if;
154	            v.Grant     := RrGrant;
155	            v.WeightCnt := to_unsigned(1, WeightWidth_g);
156	        elsif r.Valid = '1' then
157	            v.WeightCnt := v.WeightCnt + 1;
158	        end if;
159	
160	        -- Write to signal
161	        r_next <= v;
162	    end process;
163	
164	    -- *** Output Assignment ***
165	    g_latency : if (Latency_g = 1) generate
166	        Out_Valid <= r.Valid;
167	        Out_Grant <= r.Grant;
168	    end generate;
169	
170	    g_no_latency : if (Latency_g = 0) generate
171	        Out_Valid <= r_next.Valid;
172	        Out_Grant <= r_next.Grant;
173	    end generate;
174	
175	    -- *** Sequential Process ***
176	    p_seq : process (Clk) is
177	    begin
178	        if rising_edge(Clk) then
179	            r <= r_next;
180	            if Rst = '1' then
181	                r.Valid      <= '0';
182	                r.GrantIdx   <= 0;
183	                r.WeightCnt  <= (others => '0');
184	                r.Weights    <= (others => '0');
185	                r.Switchover <= '1';
186	            end if;
187	        end if;
188	    end process;
189	
190	end architecture;
191	
192

